function solve(nums) {
    const N = nums.length;
    if (N === 0) {
        return [];
    }

    // 1. Calculate LMax: LMax[i] stores the maximum element in nums[0...i-1]
    const LMax = new Array(N);
    LMax[0] = -1; // Sentinel value smaller than any possible nums[i] (min nums[i] is 1)
    let currentMax = -1;
    for (let i = 1; i < N; i++) {
        currentMax = Math.max(currentMax, nums[i - 1]);
        LMax[i] = currentMax;
    }

    // 2. Calculate RMax: RMax[i] stores the maximum element in nums[i+1...N-1]
    const RMax = new Array(N);
    RMax[N - 1] = -1; // Sentinel value
    currentMax = -1;
    for (let i = N - 2; i >= 0; i--) {
        currentMax = Math.max(currentMax, nums[i + 1]);
        RMax[i] = currentMax;
    }

    // 3. Determine Result
    const result = [];
    for (let i = 0; i < N; i++) {
        const isStrictlyGreaterLeft = nums[i] > LMax[i];
        const isStrictlyGreaterRight = nums[i] > RMax[i];

        // An element is effective if it satisfies at least one condition
        if (isStrictlyGreaterLeft || isStrictlyGreaterRight) {
            result.push(nums[i]);
        }
    }

    return result;
}

